import{_ as a,o as s,c as i,ai as o}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Voice Wake","description":"","frontmatter":{"summary":"Global voice wake words (Gateway-owned) and how they sync across nodes","read_when":["Changing voice wake words behavior or defaults","Adding new node platforms that need wake word sync"],"title":"Voice Wake"},"headers":[],"relativePath":"nodes/voicewake.md","filePath":"nodes/voicewake.md","lastUpdated":1771906665000}'),t={name:"nodes/voicewake.md"};function n(l,e,d,r,c,h){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="voice-wake-global-wake-words" tabindex="-1"><a class="header-anchor" href="#voice-wake-global-wake-words">#</a> Voice Wake (Global Wake Words)</h1><p>OpenSoul treats <strong>wake words as a single global list</strong> owned by the <strong>Gateway</strong>.</p><ul><li>There are <strong>no per-node custom wake words</strong>.</li><li><strong>Any node/app UI may edit</strong> the list; changes are persisted by the Gateway and broadcast to everyone.</li><li>Each device still keeps its own <strong>Voice Wake enabled/disabled</strong> toggle (local UX + permissions differ).</li></ul><h2 id="storage-gateway-host" tabindex="-1"><a class="header-anchor" href="#storage-gateway-host">#</a> Storage (Gateway host)</h2><p>Wake words are stored on the gateway machine at:</p><ul><li><code>~/.opensoul/settings/voicewake.json</code></li></ul><p>Shape:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;triggers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opensoul&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;claude&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;computer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;updatedAtMs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1730000000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="protocol" tabindex="-1"><a class="header-anchor" href="#protocol">#</a> Protocol</h2><h3 id="methods" tabindex="-1"><a class="header-anchor" href="#methods">#</a> Methods</h3><ul><li><code>voicewake.get</code> → <code>{ triggers: string[] }</code></li><li><code>voicewake.set</code> with params <code>{ triggers: string[] }</code> → <code>{ triggers: string[] }</code></li></ul><p>Notes:</p><ul><li>Triggers are normalized (trimmed, empties dropped). Empty lists fall back to defaults.</li><li>Limits are enforced for safety (count/length caps).</li></ul><h3 id="events" tabindex="-1"><a class="header-anchor" href="#events">#</a> Events</h3><ul><li><code>voicewake.changed</code> payload <code>{ triggers: string[] }</code></li></ul><p>Who receives it:</p><ul><li>All WebSocket clients (macOS app, WebChat, etc.)</li><li>All connected nodes (iOS/Android), and also on node connect as an initial “current state” push.</li></ul><h2 id="client-behavior" tabindex="-1"><a class="header-anchor" href="#client-behavior">#</a> Client behavior</h2><h3 id="macos-app" tabindex="-1"><a class="header-anchor" href="#macos-app">#</a> macOS app</h3><ul><li>Uses the global list to gate <code>VoiceWakeRuntime</code> triggers.</li><li>Editing “Trigger words” in Voice Wake settings calls <code>voicewake.set</code> and then relies on the broadcast to keep other clients in sync.</li></ul><h3 id="ios-node" tabindex="-1"><a class="header-anchor" href="#ios-node">#</a> iOS node</h3><ul><li>Uses the global list for <code>VoiceWakeManager</code> trigger detection.</li><li>Editing Wake Words in Settings calls <code>voicewake.set</code> (over the Gateway WS) and also keeps local wake-word detection responsive.</li></ul><h3 id="android-node" tabindex="-1"><a class="header-anchor" href="#android-node">#</a> Android node</h3><ul><li>Exposes a Wake Words editor in Settings.</li><li>Calls <code>voicewake.set</code> over the Gateway WS so edits sync everywhere.</li></ul>',24)])])}const k=a(t,[["render",n]]);export{g as __pageData,k as default};
